//! Glossolalia MOA — Mixture-of-Agents Scheduling Engine
//!
//! Implements fork/race/fold temperature-ensemble inference with COLTRANE
//! topological constraints. Core algorithm:
//!
//! FORK: Create k agents at diverse temperatures T1...Tk
//! RACE: Filter non-finite logits (safety gate)
//! FOLD: Merge via deficit-weighted complement voting
//! INTERFERE: Feedback temperature adjustment (φ-convergent)
//! COLTRANE: Optional topological constraints (fold, pitch, eddy)
//!
//! Reference: open-source/aether/src/glossolalia-moa.ts (TypeScript canonical)
//! Proof: daisy_chain_* witnesses (complement voting, deficit weighting)

use std::f32;

pub const PHI: f32 = 1.618_034;
pub const PHI_INVERSE: f32 = 1.0 / PHI;
pub const PHI_SQUARED: f32 = PHI * PHI;
const LOGIT_FLOOR: f32 = -1e9;

/// MOA configuration for temperature ensemble.
#[derive(Clone)]
pub struct MOAConfig {
    /// Number of agents (default: 3)
    pub num_agents: usize,
    /// Base temperature (agents spread around this)
    pub base_temperature: f32,
    /// Temperature spread (agents at base ± spread)
    pub temperature_spread: f32,
    /// Explicit temperatures (overrides base+spread if provided)
    pub temperatures: Option<Vec<f32>>,
    /// Merge strategy: "deficit-weighted", "uniform", "complement-vote", "winner-take-all"
    pub merge_strategy: MergeStrategy,
    /// Enable INTERFERE feedback loop
    pub interfere: bool,
    /// INTERFERE sensitivity (0-1, default 1/φ)
    pub interfere_sensitivity: f32,
    /// Enable Coltrane constraints
    pub enable_coltrane: bool,
}

#[derive(Clone, Debug)]
pub enum MergeStrategy {
    DeficitWeighted,
    Uniform,
    ComplementVote,
    WinnerTakeAll,
}

impl Default for MOAConfig {
    fn default() -> Self {
        Self {
            num_agents: 3,
            base_temperature: 0.7,
            temperature_spread: 0.4,
            temperatures: None,
            merge_strategy: MergeStrategy::DeficitWeighted,
            interfere: false,
            interfere_sensitivity: PHI_INVERSE,
            enable_coltrane: false,
        }
    }
}

/// Individual agent in the ensemble.
#[derive(Clone, Debug)]
pub struct MOAAgent {
    pub index: usize,
    pub temperature: f32,
    pub label: String,
}

/// Result of RACE filtering (non-finite detection).
pub struct FilteredAgentLogits {
    pub valid: Vec<Vec<f32>>,
    pub valid_indices: Vec<usize>,
    pub invalid_indices: Vec<usize>,
}

/// Result of FOLD (deficit-weighted merge).
pub struct MOAMergedResult {
    pub merged_logits: Vec<f32>,
    pub rejection_counts: Vec<u32>,
    pub complement_weights: Vec<f32>,
    pub deficit: usize,
    pub entropy: f32,
    pub interfere_metrics: Option<InterfereMetrics>,
}

#[derive(Clone, Debug)]
pub struct InterfereMetrics {
    pub deficit_ratio: f32,
    pub current_spread: f32,
    pub cycle: usize,
    pub phi_distance: f32,
    pub regime_change: bool,
    pub absorbing: bool,
}

/// INTERFERE state: two-register sliding window for φ-convergent feedback.
#[derive(Clone, Debug)]
pub struct InterfereState {
    pub last_deficit: f32,
    pub prev_deficit: f32,
    pub current_spread: f32,
    pub base_spread: f32,
    pub deficit_ratio: f32,
    pub cycle: usize,
    pub entropy_history: Vec<f32>,
    pub repeat_count: usize,
    pub last_token_id: i32,
}

impl InterfereState {
    pub fn new(base_spread: f32) -> Self {
        Self {
            last_deficit: 1.0,
            prev_deficit: 1.0,
            current_spread: base_spread,
            base_spread,
            deficit_ratio: 1.0,
            cycle: 0,
            entropy_history: Vec::new(),
            repeat_count: 0,
            last_token_id: -1,
        }
    }
}

/// INTERFERE: fold observing the fork.
/// High deficit → widen temperature spread (need diversity)
/// Low deficit → narrow spread (converging, tighten focus)
/// Deficit ratio converges to φ (golden ratio eigenvalue).
pub fn interfere(
    state: &mut InterfereState,
    current_deficit: f32,
    current_entropy: f32,
    selected_token_id: i32,
    sensitivity: f32,
) {
    // === Lane 0: VENT -- slide the window ===
    let new_prev_deficit = state.last_deficit;
    let new_last_deficit = current_deficit;

    // === Lane 1: INTERFERE -- compute deficit ratio ===
    let deficit_ratio = if new_prev_deficit > 0.0 {
        new_last_deficit / new_prev_deficit
    } else {
        1.0
    };

    // === Lane 2: C2 -- entropy regime detection ===
    state.entropy_history.push(current_entropy);
    if state.entropy_history.len() > 5 {
        state.entropy_history.remove(0);
    }
    let regime_change = {
        if state.entropy_history.len() >= 3 {
            let recent = state.entropy_history[state.entropy_history.len() - 1];
            let older = state.entropy_history[state.entropy_history.len() - 3];
            older > 0.0 && recent < older * 0.5
        } else {
            false
        }
    };

    // === Lane 3: C3 -- absorbing-state detection ===
    let mut repeat_count = state.repeat_count;
    if selected_token_id == state.last_token_id {
        repeat_count += 1;
    } else {
        repeat_count = 0;
    }
    let absorbing = repeat_count >= 3;

    // === FOLD: compute new temperature spread ===
    let mut spread_multiplier = 1.0;
    if regime_change || absorbing {
        spread_multiplier = PHI;
    } else if deficit_ratio > PHI {
        spread_multiplier = 1.0 + (sensitivity * (deficit_ratio - PHI)) / PHI;
    } else if deficit_ratio < PHI_INVERSE {
        spread_multiplier = 1.0 - sensitivity * (PHI_INVERSE - deficit_ratio);
    }

    let new_spread = (state.current_spread * spread_multiplier)
        .max(state.base_spread * 0.1)
        .min(state.base_spread * PHI_SQUARED);

    state.last_deficit = new_last_deficit;
    state.prev_deficit = new_prev_deficit;
    state.current_spread = new_spread;
    state.deficit_ratio = deficit_ratio;
    state.cycle += 1;
    state.repeat_count = repeat_count;
    state.last_token_id = selected_token_id;
}

/// Create MOA agents from config.
pub fn create_moa_agents(config: &MOAConfig) -> Vec<MOAAgent> {
    let mut agents = Vec::new();
    let num_agents = config.num_agents;

    if let Some(temps) = &config.temperatures {
        if temps.len() >= num_agents {
            for i in 0..num_agents {
                agents.push(MOAAgent {
                    index: i,
                    temperature: temps[i],
                    label: format!("agent-{}-t{:.2}", i, temps[i]),
                });
            }
            return agents;
        }
    }

    let base = config.base_temperature;
    let spread = config.temperature_spread;

    for i in 0..num_agents {
        let t = if num_agents == 1 {
            base
        } else {
            base - spread + (2.0 * spread * i as f32) / (num_agents - 1) as f32
        };
        let t = t.max(0.01);
        agents.push(MOAAgent {
            index: i,
            temperature: t,
            label: format!("agent-{}-t{:.2}", i, t),
        });
    }

    agents
}

/// RACE: Filter agents with non-finite logits (safety gate).
pub fn filter_finite_agents(
    agent_logits: &[Vec<f32>],
    agent_indices: Option<&[usize]>,
) -> FilteredAgentLogits {
    let mut valid = Vec::new();
    let mut valid_indices = Vec::new();
    let mut invalid_indices = Vec::new();

    for (a, logits) in agent_logits.iter().enumerate() {
        let agent_index = agent_indices.map(|indices| indices[a]).unwrap_or(a);

        if logits.iter().any(|&l| !l.is_finite()) {
            invalid_indices.push(agent_index);
        } else {
            valid.push(logits.clone());
            valid_indices.push(agent_index);
        }
    }

    FilteredAgentLogits {
        valid,
        valid_indices,
        invalid_indices,
    }
}

/// Stable softmax entropy from logits.
pub fn stable_softmax_entropy(logits: &[f32]) -> f32 {
    if logits.is_empty() {
        return 0.0;
    }

    let max_logit = logits
        .iter()
        .filter(|&&l| l.is_finite())
        .cloned()
        .fold(f32::NEG_INFINITY, f32::max);

    if !max_logit.is_finite() {
        return 0.0;
    }

    let mut sum_exp = 0.0;
    let mut sum_exp_log = 0.0;

    for &l in logits {
        let val = if l.is_finite() { l } else { 0.0 };
        let exp_val = (val - max_logit).exp();
        sum_exp += exp_val;
        sum_exp_log += exp_val * (val - max_logit);
    }

    if sum_exp <= 0.0 {
        return 0.0;
    }

    (sum_exp_log / sum_exp + max_logit).max(0.0)
}

/// FOLD: Deficit-weighted merge with complement voting.
pub fn deficit_weighted_merge(
    agent_logits: &[Vec<f32>],
    vocab_size: usize,
    strategy: &MergeStrategy,
    use_kl: bool,
) -> MOAMergedResult {
    let k = agent_logits.len();

    if k == 0 {
        return MOAMergedResult {
            merged_logits: vec![0.0; vocab_size],
            rejection_counts: vec![0; vocab_size],
            complement_weights: vec![1.0; vocab_size],
            deficit: 0,
            entropy: 0.0,
            interfere_metrics: None,
        };
    }

    if k == 1 {
        let only_agent = &agent_logits[0];
        let merged = copy_finite_logits(only_agent, vocab_size);
        let entropy = stable_softmax_entropy(&merged);
        return MOAMergedResult {
            merged_logits: merged,
            rejection_counts: vec![0; vocab_size],
            complement_weights: vec![1.0; vocab_size],
            deficit: 0,
            entropy,
            interfere_metrics: None,
        };
    }

    // === Step 1: Count rejections per token ===
    let mut rejection_counts = vec![0u32; vocab_size];
    for logits in agent_logits {
        let mean = logits.iter().take(vocab_size).sum::<f32>() / vocab_size.max(1) as f32;

        for i in 0..vocab_size {
            let val = logits.get(i).copied().unwrap_or(f32::NEG_INFINITY);
            if val < mean {
                rejection_counts[i] = rejection_counts[i].saturating_add(1);
            }
        }
    }

    // === Step 2: Complement weights ===
    let mut complement_weights = vec![0.0; vocab_size];
    for i in 0..vocab_size {
        let rejections = rejection_counts[i] as usize;
        complement_weights[i] = (k - rejections.min(k) + 1) as f32;
    }

    // === Step 3: Merge based on strategy ===
    let merged_logits = match strategy {
        MergeStrategy::Uniform => {
            let mut merged = vec![0.0; vocab_size];
            for i in 0..vocab_size {
                let mut sum = 0.0;
                for logits in agent_logits {
                    sum += logits.get(i).copied().unwrap_or(0.0);
                }
                merged[i] = (sum / k as f32) * complement_weights[i];
            }
            merged
        }
        MergeStrategy::DeficitWeighted => {
            let deficits = compute_agent_deficits(agent_logits, vocab_size, use_kl);
            let mut merged = vec![0.0; vocab_size];
            for i in 0..vocab_size {
                let mut weighted_sum = 0.0;
                let mut total_deficit = 0.0;
                for (a, logits) in agent_logits.iter().enumerate() {
                    let deficit_weight = deficits[a];
                    let val = logits.get(i).copied().unwrap_or(0.0);
                    weighted_sum += val * deficit_weight;
                    total_deficit += deficit_weight;
                }
                merged[i] = if total_deficit > 0.0 {
                    (weighted_sum / total_deficit) * complement_weights[i]
                } else {
                    0.0
                };
            }
            merged
        }
        MergeStrategy::ComplementVote => complement_weights.clone(),
        MergeStrategy::WinnerTakeAll => {
            let mut min_rejections = usize::MAX;
            let mut winner = 0;
            for i in 0..vocab_size {
                let rejections = rejection_counts[i] as usize;
                if rejections < min_rejections {
                    min_rejections = rejections;
                    winner = i;
                }
            }
            let mut merged = vec![LOGIT_FLOOR; vocab_size];
            merged[winner] = 0.0;
            merged
        }
    };

    let entropy = stable_softmax_entropy(&merged_logits);

    MOAMergedResult {
        merged_logits,
        rejection_counts,
        complement_weights,
        deficit: k - 1,
        entropy,
        interfere_metrics: None,
    }
}

/// Compute per-agent deficit weights (L2 or KL divergence).
fn compute_agent_deficits(agent_logits: &[Vec<f32>], vocab_size: usize, use_kl: bool) -> Vec<f32> {
    let k = agent_logits.len();
    let mut deficits = vec![0.0; k];

    if use_kl {
        // KL-divergence from uniform distribution
        let uniform_prob = 1.0 / vocab_size as f32;

        for (a, logits) in agent_logits.iter().enumerate() {
            let max_logit = logits
                .iter()
                .take(vocab_size)
                .filter(|&&l| l.is_finite())
                .cloned()
                .fold(f32::NEG_INFINITY, f32::max);

            if !max_logit.is_finite() {
                deficits[a] = 1e-6;
                continue;
            }

            let mut sum_exp = 0.0;
            let mut probs = vec![0.0; vocab_size];
            for i in 0..vocab_size {
                let val = logits.get(i).copied().unwrap_or(0.0);
                probs[i] = (val - max_logit).exp();
                sum_exp += probs[i];
            }

            let mut kl = 0.0;
            for i in 0..vocab_size {
                let p = if sum_exp > 0.0 {
                    probs[i] / sum_exp
                } else {
                    0.0
                };
                if p > 1e-10 {
                    kl += p * (p / uniform_prob).ln();
                }
            }

            deficits[a] = kl.max(1e-6) + 1.0;
        }
    } else {
        // L2 divergence from ensemble mean
        let mut mean = vec![0.0; vocab_size];
        for logits in agent_logits {
            for i in 0..vocab_size {
                mean[i] += logits.get(i).copied().unwrap_or(0.0);
            }
        }
        for i in 0..vocab_size {
            mean[i] /= k as f32;
        }

        for (a, logits) in agent_logits.iter().enumerate() {
            let mut divergence = 0.0;
            for i in 0..vocab_size {
                let val = logits.get(i).copied().unwrap_or(0.0);
                let diff = val - mean[i];
                divergence += diff * diff;
            }
            deficits[a] = divergence.sqrt() + 1.0;
        }
    }

    // Normalize to sum to 1
    let total: f32 = deficits.iter().sum();
    if total > 0.0 {
        for d in &mut deficits {
            *d /= total;
        }
    }

    deficits
}

/// Copy logits ensuring all values are finite.
fn copy_finite_logits(logits: &[f32], vocab_size: usize) -> Vec<f32> {
    let mut copy = vec![0.0; vocab_size];
    for i in 0..vocab_size {
        copy[i] = logits
            .get(i)
            .copied()
            .filter(|l| l.is_finite())
            .unwrap_or(0.0);
    }
    copy
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_create_moa_agents() {
        let config = MOAConfig {
            num_agents: 3,
            base_temperature: 0.7,
            temperature_spread: 0.4,
            ..Default::default()
        };

        let agents = create_moa_agents(&config);
        assert_eq!(agents.len(), 3);
        assert!(agents[0].temperature < agents[1].temperature);
        assert!(agents[1].temperature < agents[2].temperature);
    }

    #[test]
    fn test_filter_finite_agents() {
        let agent_logits = vec![
            vec![1.0, 2.0, 3.0],
            vec![f32::NAN, 2.0, 3.0],
            vec![1.0, 2.0, 3.0],
        ];

        let filtered = filter_finite_agents(&agent_logits, None);
        assert_eq!(filtered.valid.len(), 2);
        assert_eq!(filtered.invalid_indices.len(), 1);
    }

    #[test]
    fn test_deficit_weighted_merge() {
        let agent_logits = vec![
            vec![1.0, 2.0, 3.0],
            vec![3.0, 2.0, 1.0],
            vec![2.0, 1.0, 3.0],
        ];

        let result = deficit_weighted_merge(&agent_logits, 3, &MergeStrategy::Uniform, false);
        assert_eq!(result.deficit, 2);
        assert!(result.merged_logits.iter().all(|l| l.is_finite()));
    }

    #[test]
    fn test_interfere_state() {
        let mut state = InterfereState::new(0.4);
        interfere(&mut state, 1.5, 1.0, 0, PHI_INVERSE);

        assert!(state.cycle > 0);
        assert_eq!(state.repeat_count, 0);
    }
}
